// Gera um load_id único por arquivo processado e registra metadados da execução.
// O load_id é a chave estável usada em pipeline_runs, ingestion_log, quarantine_rows e fact_financials.
const binProp = 'data';
const bin = $binary[binProp];
const sourceFile = (bin && bin.fileName) ? bin.fileName : `desconhecido_${$itemIndex}.xlsx`;

// load_id determinístico-ish: timestamp + nome do arquivo + índice (evita colisão no mesmo run)
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const stamp = `${now.getUTCFullYear()}${pad(now.getUTCMonth() + 1)}${pad(now.getUTCDate())}${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}${pad(now.getUTCSeconds())}`;
const slug = sourceFile.replace(/[^a-zA-Z0-9]+/g, '_').slice(0, 40);
const loadId = `LOAD_${stamp}_${slug}_${$itemIndex}`;

return {
  json: {
    load_id: loadId,
    workflow: '01_ingestao_planilhas',
    source_file: sourceFile,
    started_at: now.toISOString(),
    status: 'RUNNING',
  },
  binary: $input.item.binary,
};

// O nó Spreadsheet perde o load_id/source_file do item original. Recuperamos do nó anterior
// e anexamos a todas as linhas, além de numerá-las (row_num) para rastreabilidade na quarentena.
const meta = $('Abrir Run do Pipeline').first().json;
const loadId = meta.load_id;
const sourceFile = meta.source_file;

const items = $input.all();
return items.map((item, idx) => ({
  json: {
    ...item.json,
    __load_id: loadId,
    __source_file: sourceFile,
    __row_num: idx + 2, // +2: linha 1 é cabeçalho, linhas de dados começam em 2
  },
}));

// Consolida contagens do run (uma execução = um arquivo) e prepara o fechamento.
const meta = $('Abrir Run do Pipeline').first().json;
let rowsOk = 0, rowsQuarantined = 0;
try { rowsOk = $('Validar — Válidas').all().length; } catch (e) { rowsOk = 0; }
try { rowsQuarantined = $('Validar — Inválidas').all().length; } catch (e) { rowsQuarantined = 0; }
const rowsTotal = rowsOk + rowsQuarantined;
const status = rowsQuarantined > 0 ? 'PARTIAL' : 'OK';   // CHECK: RUNNING|OK|PARTIAL|ERROR
return [{
  json: {
    load_id: meta.load_id,
    workflow: meta.workflow,
    source_file: meta.source_file,
    rows_total: rowsTotal,
    rows_ok: rowsOk,
    rows_quarantined: rowsQuarantined,
    status,
    finished_at: new Date().toISOString(),
    message: `${rowsOk}/${rowsTotal} carregadas, ${rowsQuarantined} em quarentena.`,
  },
}];

// Extrai detalhes do erro do Error Trigger para registrar em ingestion_log e marcar o run como FAILED.
const err = $json;
const execErr = (err.execution && err.execution.error) || {};
const lastNode = (err.execution && err.execution.lastNodeExecuted) || 'desconhecido';

// Tenta recuperar o load_id do contexto da execução que falhou (se disponível).
let loadId = 'DESCONHECIDO';
try {
  const inputData = err.execution && err.execution.data;
  // Fallback: o load_id pode não estar acessível; registramos o que houver.
  loadId = (err.workflow && err.workflow.id) ? `WF_${err.workflow.id}_FALHA` : 'DESCONHECIDO';
} catch (e) {
  loadId = 'DESCONHECIDO';
}

return {
  json: {
    load_id: loadId,
    level: 'ERROR',
    step: lastNode,
    message: execErr.message || 'Falha não tratada no pipeline de ingestão',
    payload: {
      node: lastNode,
      error_message: execErr.message || null,
      error_stack: execErr.stack || null,
      execution_id: (err.execution && err.execution.id) || null,
      workflow_name: (err.workflow && err.workflow.name) || null,
    },
  },
};

// ====================================================================================
// VALIDAÇÃO DE SCHEMA (Fase 1) — conforme SPEC.md
// Regras:
//   1. Colunas obrigatórias presentes
//   2. period (period_date) parseável para 1º dia do mês (DATE)
//   3. valor (valor_realizado) numérico
//   4. valor_orcado numérico (se presente; default 0)
//   5. account_code pertence ao conjunto conhecido (dim_account)
//   6. company_id pertence ao conjunto conhecido (dim_company)
// Linhas válidas -> saída 0 (válidas). Linhas inválidas -> saída 1 (quarentena).
// ====================================================================================

// Conjuntos conhecidos (espelham cockpit.dim_account e cockpit.dim_company do SPEC).
const KNOWN_ACCOUNTS = new Set([
  // P&L (PNL)
  'R_BRUTA', 'DEDUCOES', 'CMV', 'DESP_PESSOAL', 'DESP_VENDAS', 'DESP_ADM',
  'DESP_OUTRAS', 'DEPRECIACAO', 'RESULT_FIN', 'IRPJ_CSLL',
  // Posição (POSICAO)
  'CAIXA', 'AR', 'AP', 'ESTOQUE', 'DIVIDA', 'PATRIMONIO',
]);

const KNOWN_COMPANIES = new Set([
  'AUR-VAR', 'AUR-IND', 'AUR-SVC', 'AUR-LOG', 'AUR-HLD', 'ELIM',
]);

// Aceita sinônimos comuns de cabeçalho (PT-BR) para robustez.
// Resolve NOME da empresa -> company_id (as planilhas trazem o nome na coluna "empresa").
const COMPANY_BY_NAME = {
  'AURORA VAREJO S.A.': 'AUR-VAR',
  'AURORA INDÚSTRIA LTDA.': 'AUR-IND',
  'AURORA SERVIÇOS LTDA.': 'AUR-SVC',
  'AURORA LOGÍSTICA LTDA.': 'AUR-LOG',
  'AURORA PARTICIPAÇÕES S.A.': 'AUR-HLD',
  'ELIMINAÇÕES INTERCOMPANY': 'ELIM',
};
function resolveCompany(v) {
  if (!v) return null;
  const u = String(v).trim().toUpperCase();
  if (KNOWN_COMPANIES.has(u)) return u;
  return COMPANY_BY_NAME[u] || null;
}

function pick(obj, keys) {
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== '') {
      return String(obj[k]).trim();
    }
  }
  return null;
}

function parsePeriod(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  // Formatos aceitos: YYYY-MM, YYYY-MM-DD, MM/YYYY, DD/MM/YYYY
  let y, m;
  let match;
  if ((match = s.match(/^(\d{4})-(\d{2})(?:-(\d{2}))?$/))) {
    y = parseInt(match[1], 10); m = parseInt(match[2], 10);
  } else if ((match = s.match(/^(\d{2})\/(\d{4})$/))) {
    m = parseInt(match[1], 10); y = parseInt(match[2], 10);
  } else if ((match = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/))) {
    m = parseInt(match[2], 10); y = parseInt(match[3], 10);
  } else {
    return null;
  }
  if (m < 1 || m > 12 || y < 2000 || y > 2100) return null;
  // Normaliza para o 1º dia do mês (grão mensal do SPEC).
  return `${y}-${String(m).padStart(2, '0')}-01`;
}

function parseNumber(raw) {
  if (raw === null || raw === undefined || String(raw).trim() === '') return null;
  let s = String(raw).trim();
  // Remove símbolo de moeda e espaços.
  s = s.replace(/R\$/gi, '').replace(/\s/g, '');
  // Formato pt-BR: 1.234.567,89  -> remove pontos (milhar), troca vírgula por ponto.
  if (/,\d{1,2}$/.test(s) || (s.includes('.') && s.includes(','))) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else {
    // Formato simples; vírgula como decimal isolada.
    s = s.replace(',', '.');
  }
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

const REQUIRED = ['company_id', 'period', 'account_code', 'valor'];
const valid = [];
const invalid = [];

for (const item of $input.all()) {
  const row = item.json;
  const loadId = row.__load_id;
  const sourceFile = row.__source_file;
  const rowNum = row.__row_num;

  // Normaliza colunas com sinônimos PT-BR.
  const companyId = pick(row, ['company_id', 'empresa', 'companyId', 'cod_empresa']);
  const periodRaw = pick(row, ['period', 'period_date', 'periodo', 'competencia', 'mes']);
  const accountCode = pick(row, ['account_code', 'conta_codigo', 'conta', 'codigo_conta', 'accountCode']);
  const valorRaw = pick(row, ['valor', 'valor_realizado', 'realizado', 'value']);
  const valorOrcadoRaw = pick(row, ['valor_orcado', 'orcado', 'budget', 'valor_orcamento']);

  const errors = [];

  // 1. Colunas obrigatórias
  if (!companyId) errors.push({ code: 'MISSING_COMPANY_ID', detail: 'company_id ausente ou vazio' });
  if (!periodRaw) errors.push({ code: 'MISSING_PERIOD', detail: 'period ausente ou vazio' });
  if (!accountCode) errors.push({ code: 'MISSING_ACCOUNT_CODE', detail: 'account_code ausente ou vazio' });
  if (valorRaw === null) errors.push({ code: 'MISSING_VALOR', detail: 'valor ausente ou vazio' });

  // 2. period parseável
  const periodDate = parsePeriod(periodRaw);
  if (periodRaw && !periodDate) {
    errors.push({ code: 'INVALID_PERIOD', detail: `period '${periodRaw}' não é uma competência válida` });
  }

  // 3. valor numérico
  const valorRealizado = parseNumber(valorRaw);
  if (valorRaw !== null && valorRealizado === null) {
    errors.push({ code: 'INVALID_VALOR', detail: `valor '${valorRaw}' não é numérico` });
  }

  // 4. valor_orcado numérico (opcional, default 0)
  let valorOrcado = 0;
  if (valorOrcadoRaw !== null) {
    const parsed = parseNumber(valorOrcadoRaw);
    if (parsed === null) {
      errors.push({ code: 'INVALID_VALOR_ORCADO', detail: `valor_orcado '${valorOrcadoRaw}' não é numérico` });
    } else {
      valorOrcado = parsed;
    }
  }

  // 5. account_code conhecido
  if (accountCode && !KNOWN_ACCOUNTS.has(accountCode.toUpperCase())) {
    errors.push({ code: 'UNKNOWN_ACCOUNT_CODE', detail: `account_code '${accountCode}' não está em dim_account` });
  }

  // 6. company_id conhecido
  const resolvedCompany = resolveCompany(companyId);
  if (companyId && !resolvedCompany) {
    errors.push({ code: 'UNKNOWN_COMPANY_ID', detail: `company_id '${companyId}' não está em dim_company` });
  }

  if (errors.length === 0) {
    valid.push({
      json: {
        load_id: loadId,
        source_file: sourceFile,
        row_num: rowNum,
        company_id: resolvedCompany,
        period_date: periodDate,
        account_code: accountCode.toUpperCase(),
        valor_realizado: valorRealizado,
        valor_orcado: valorOrcado,
      },
    });
  } else {
    invalid.push({
      json: {
        load_id: loadId,
        source_file: sourceFile,
        row_num: rowNum,
        raw_payload: row,
        error_code: errors[0].code,
        error_detail: errors.map((e) => `${e.code}: ${e.detail}`).join(' | '),
      },
    });
  }
}

// Saída 0 = válidas; Saída 1 = inválidas (quarentena).
return valid;   // saída única: apenas linhas VÁLIDAS (-> stg_financials)

